#!/usr/bin/env bash
# experiments/orchestrate/aggregate.sh
#
# Post-run aggregator for the fiat-crypto proof-evaluation pipeline
# (epic #27 / issue #21). For a completed run of run-commit.sh against a
# compose.yml generated by gen-compose.py, this script:
#
#   1. Enumerates every named `results-<sha-prefix>` volume declared in the
#      run's compose.yml (source of truth — NOT `docker volume ls`).
#   2. Copies each volume's `<run_id>/` subtree out to
#      `experiments/results/<run_id>/raw/<sha-prefix>/` via a throwaway
#      alpine container.
#   3. Concatenates per-SHA `agent.jsonl` / `baseline.jsonl` into top-level
#      aggregates under `experiments/results/<run_id>/`.
#   4. Updates the atomic `experiments/results/latest -> <run_id>` symlink.
#   5. Invokes `summary.py` to emit `summary.json` + `summary.md`.
#
# Usage:
#   ./aggregate.sh [<run_id>] [--dry-run] [--skip-copy]
#
# If <run_id> is omitted, defaults to the newest
# `experiments/results/<run_id>/` dir by lexicographic sort (the run_id
# format YYYYMMDD-HHMMSS sorts chronologically).
#
# --dry-run  Prints the docker copy commands, the planned concatenations,
#            and the planned summary.py invocation without executing any
#            of them. Works with docker absent.
# --skip-copy
#            Skip the docker volume copy phase. Useful when the per-SHA
#            data has already been staged under raw/ by some other
#            mechanism (notably, the test harness). Everything else
#            (concatenation, symlink, summary.py) still runs.
#
# Idempotency: re-running against the same <run_id> must succeed and
# produce identical outputs. The docker copy uses `cp -a /in/<run_id>/.`
# which overwrites files in place; the concat steps unconditionally
# rewrite the top-level aggregates; `ln -snf` atomically replaces the
# `latest` symlink.
#
# Volumes are NEVER removed; operators can re-run aggregation if
# summary.py fails (or tweaks summary.py and re-aggregates).

set -euo pipefail
shopt -s nullglob

# ---------------------------------------------------------------------------
# Paths
# ---------------------------------------------------------------------------
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
EXPERIMENTS_ROOT="$(cd "${SCRIPT_DIR}/.." && pwd)"
REPO_ROOT="$(cd "${EXPERIMENTS_ROOT}/.." && pwd)"
RESULTS_ROOT="${EXPERIMENTS_ROOT}/results"

# Image used for the in-volume copy. Small, hermetic, pre-installed
# nearly-everywhere-in-CI. Overridable via env for air-gapped workflows.
COPY_IMAGE="${AGGREGATE_COPY_IMAGE:-alpine:3.19}"

# ---------------------------------------------------------------------------
# Defaults / globals
# ---------------------------------------------------------------------------
RUN_ID=""
DRY_RUN=0
SKIP_COPY=0

# ---------------------------------------------------------------------------
# Logging helpers (stderr; matches build-images.sh / run-commit.sh style)
# ---------------------------------------------------------------------------
log()  { printf '[aggregate] %s\n' "$*" >&2; }
warn() { printf '[aggregate] WARN: %s\n' "$*" >&2; }
die()  { printf '[aggregate] ERROR: %s\n' "$*" >&2; exit 1; }

usage() {
  cat <<'EOF'
Usage: aggregate.sh [<run_id>] [OPTIONS]

Arguments:
  <run_id>               Run identifier. If omitted, defaults to the newest
                         experiments/results/<id>/ directory whose name
                         matches YYYYMMDD-HHMMSS (lexicographically sorted).

Options:
  --dry-run              Print the docker copy commands, the planned
                         concatenations, and the summary.py invocation
                         without executing any of them. Works with docker
                         absent.
  --skip-copy            Skip the docker volume copy phase. The
                         concatenation + symlink + summary.py steps still
                         run. Primarily a test hook.
  -h, --help             Show this help and exit.

Behavior:
  1. Enumerates `results-<sha-prefix>` volumes from
     experiments/results/<run_id>/compose.yml via
       docker compose -f <compose> config --format json | jq '.volumes|keys[]'
     (source of truth is the compose file, not `docker volume ls`).
  2. For each volume, spins up a throwaway alpine container that copies
     /in/<run_id>/ (the volume) into
       experiments/results/<run_id>/raw/<sha-prefix>/
     The `|| true` tolerates volumes whose container crashed before
     writing anything — we don't want one failed SHA to abort the whole
     aggregation.
  3. Concatenates raw/*/agent.jsonl and raw/*/baseline.jsonl into the
     top-level experiments/results/<run_id>/{agent,baseline}.jsonl.
     Empty outputs (no per-SHA subdirs, no data) are fine — summary.py
     will print a diagnostic and the aggregator will surface it.
  4. Invokes summary.py (no console script; we call the file directly
     via `uv run python summary.py`).
  5. ln -snf <run_id> experiments/results/latest — atomic replacement.

Environment:
  AGGREGATE_COPY_IMAGE   Container image used for the volume -> host copy.
                         Default: alpine:3.19.
EOF
}

# ---------------------------------------------------------------------------
# Argument parsing
# ---------------------------------------------------------------------------
parse_args() {
  local -a positionals=()

  while [ "$#" -gt 0 ]; do
    case "$1" in
      -h|--help)
        usage
        exit 0
        ;;
      --dry-run)
        DRY_RUN=1
        shift
        ;;
      --skip-copy)
        SKIP_COPY=1
        shift
        ;;
      --)
        shift
        while [ "$#" -gt 0 ]; do
          positionals+=("$1")
          shift
        done
        ;;
      -*)
        usage >&2
        die "unknown option: $1"
        ;;
      *)
        positionals+=("$1")
        shift
        ;;
    esac
  done

  if [ "${#positionals[@]}" -gt 1 ]; then
    usage >&2
    die "expected at most 1 positional argument (<run_id>); got ${#positionals[@]}"
  fi

  if [ "${#positionals[@]}" -eq 1 ]; then
    RUN_ID="${positionals[0]}"
    case "${RUN_ID}" in
      *[!A-Za-z0-9._-]*)
        die "<run_id> may only contain [A-Za-z0-9._-]; got '${RUN_ID}'"
        ;;
    esac
  fi
}

# ---------------------------------------------------------------------------
# Run-id selection
# ---------------------------------------------------------------------------
# If RUN_ID is empty, pick the newest YYYYMMDD-HHMMSS directory under
# experiments/results/. Dies with a helpful message when no such dir exists.
default_run_id() {
  local newest
  newest="$(
    ls -1 "${RESULTS_ROOT}" 2>/dev/null \
      | grep -E '^[0-9]{8}-[0-9]{6}$' \
      | sort -r \
      | head -n 1 \
      || true
  )"
  if [ -z "${newest}" ]; then
    die "no <run_id> given and no YYYYMMDD-HHMMSS directories under ${RESULTS_ROOT}"
  fi
  printf '%s' "${newest}"
}

# ---------------------------------------------------------------------------
# Volume enumeration from compose.yml
# ---------------------------------------------------------------------------
# Prints the list of `results-<prefix>` volume names (one per line) declared
# in the given compose file. Uses `docker compose config --format json` to
# resolve anchors + env interpolation, then jq to pull out the top-level
# `volumes:` keys. Source of truth is the compose file, NOT `docker volume ls`.
enumerate_volumes() {
  local compose_file="$1"
  if [ ! -f "${compose_file}" ]; then
    die "compose file not found: ${compose_file}
(hint: did gen-compose.py run? expected at experiments/results/${RUN_ID}/compose.yml)"
  fi
  if ! command -v jq >/dev/null 2>&1; then
    die "jq is required but not found on PATH"
  fi
  if ! command -v docker >/dev/null 2>&1; then
    die "docker is required for --format json volume enumeration (use --skip-copy to bypass the copy phase, but enumeration still needs docker compose to parse the file)"
  fi

  docker compose -f "${compose_file}" config --format json \
    | jq -r '.volumes | keys[]'
}

# ---------------------------------------------------------------------------
# Copy phase
# ---------------------------------------------------------------------------
# $1: volume name (results-<prefix>)
# $2: sha prefix (derived from volume name)
# $3: run_id
# $4: absolute path to raw/ dir on the host
#
# Spins up a throwaway alpine container that mounts the volume read-ish and
# copies /in/<run_id>/. (note the trailing /.) into /out/<prefix>/. The
# `|| true` at the end of the inner sh -c tolerates a volume that never got
# written to (container crashed before the prelude `mkdir -p /results/<run_id>`
# completed). We still produce an empty /out/<prefix>/ dir so downstream
# globbing has a consistent shape.
copy_volume() {
  local volume="$1"
  local prefix="$2"
  local run_id="$3"
  local raw_dir="$4"

  local -a docker_cmd=(
    docker run --rm
    -v "${volume}:/in"
    -v "${raw_dir}:/out"
    "${COPY_IMAGE}"
    sh -c "mkdir -p /out/${prefix} && cp -a /in/${run_id}/. /out/${prefix}/ 2>/dev/null || true"
  )

  if [ "${DRY_RUN}" -eq 1 ]; then
    log "DRY-RUN: ${docker_cmd[*]}"
    return 0
  fi

  log "copying volume ${volume} -> ${raw_dir}/${prefix}/"
  "${docker_cmd[@]}"
}

# ---------------------------------------------------------------------------
# Concatenation
# ---------------------------------------------------------------------------
# $1: run dir (experiments/results/<run_id>)
#
# Concatenates raw/*/agent.jsonl -> agent.jsonl and raw/*/baseline.jsonl ->
# baseline.jsonl at the top level. If no per-SHA subdirs wrote a given mode,
# produces an empty file (shopt -s nullglob is set at the top of the script
# so an unmatched glob expands to nothing rather than the literal glob).
concat_jsonls() {
  local run_dir="$1"
  local mode src_glob dest
  for mode in agent baseline; do
    dest="${run_dir}/${mode}.jsonl"
    # shellcheck disable=SC2206 # nullglob handles the no-match case
    local -a srcs=( "${run_dir}/raw"/*/"${mode}.jsonl" )

    if [ "${DRY_RUN}" -eq 1 ]; then
      if [ "${#srcs[@]}" -eq 0 ]; then
        log "DRY-RUN: (no ${mode}.jsonl sources under ${run_dir}/raw/*/) -> would create empty ${dest}"
      else
        log "DRY-RUN: cat ${srcs[*]} > ${dest}"
      fi
      continue
    fi

    if [ "${#srcs[@]}" -eq 0 ]; then
      : > "${dest}"
      log "no per-SHA ${mode}.jsonl files under ${run_dir}/raw/*/; wrote empty ${dest}"
    else
      cat "${srcs[@]}" > "${dest}"
      log "concatenated ${#srcs[@]} ${mode}.jsonl file(s) -> ${dest}"
    fi
  done
}

# ---------------------------------------------------------------------------
# Summary invocation
# ---------------------------------------------------------------------------
# $1: run_id
#
# summary.py's --inputs is a shell-style glob expanded by Python (globlib).
# Since we `cd experiments`, all paths are relative to experiments/. The
# summary-invocation pyproject.toml has `eval-baseline` / `eval-agent`
# scripts but NOT a `summary` console script, so we call the file directly.
#
# summary.py exits 1 when no files match its --inputs glob. That can happen
# when every volume was empty; we tolerate it with a clear diagnostic rather
# than crashing the aggregator.
run_summary() {
  local run_id="$1"
  local inputs="results/${run_id}/*.jsonl"
  local out="results/${run_id}/summary.json"
  local md="results/${run_id}/summary.md"

  local -a cmd=(
    uv run python summary.py
    --inputs "${inputs}"
    --out "${out}"
    --markdown "${md}"
  )

  if [ "${DRY_RUN}" -eq 1 ]; then
    log "DRY-RUN: (cd ${EXPERIMENTS_ROOT} && ${cmd[*]})"
    return 0
  fi

  log "running: (cd ${EXPERIMENTS_ROOT} && ${cmd[*]})"
  local rc=0
  ( cd "${EXPERIMENTS_ROOT}" && "${cmd[@]}" ) || rc=$?
  if [ "${rc}" -ne 0 ]; then
    warn "summary.py exited ${rc} (typically: no input JSONL files matched, or malformed input). summary.json/summary.md may not have been written."
  fi
  return "${rc}"
}

# ---------------------------------------------------------------------------
# Latest symlink
# ---------------------------------------------------------------------------
# ln -snf <target> <link>:
#   -s  symbolic
#   -n  treat existing symlink-to-dir as a file (don't descend into it)
#   -f  force-replace
# Together this gives an atomic swap of the symlink target.
update_latest_symlink() {
  local run_id="$1"
  local link="${RESULTS_ROOT}/latest"

  if [ "${DRY_RUN}" -eq 1 ]; then
    log "DRY-RUN: ln -snf ${run_id} ${link}"
    return 0
  fi

  ln -snf "${run_id}" "${link}"
  log "updated symlink: ${link} -> ${run_id}"
}

# ---------------------------------------------------------------------------
# Line counter (post-concat diagnostic)
# ---------------------------------------------------------------------------
line_count() {
  local f="$1"
  if [ ! -f "${f}" ]; then
    printf '0'
    return 0
  fi
  wc -l < "${f}" | tr -d ' '
}

# ---------------------------------------------------------------------------
# Main
# ---------------------------------------------------------------------------
main() {
  parse_args "$@"

  if [ -z "${RUN_ID}" ]; then
    RUN_ID="$(default_run_id)"
    log "no <run_id> given; defaulting to newest: ${RUN_ID}"
  fi

  local run_dir="${RESULTS_ROOT}/${RUN_ID}"
  local compose_file="${run_dir}/compose.yml"
  local raw_dir="${run_dir}/raw"

  if [ ! -d "${run_dir}" ]; then
    die "run directory not found: ${run_dir}
(hint: the run_id must match an existing experiments/results/<id>/ dir)"
  fi

  # raw_dir is created unconditionally so the docker mount has a host-side
  # target (docker would otherwise create it as root-owned).
  mkdir -p "${raw_dir}"

  # -----------------------------------------------------------------------
  # Volume copy phase
  # -----------------------------------------------------------------------
  if [ "${SKIP_COPY}" -eq 1 ]; then
    log "--skip-copy: skipping volume enumeration + copy phase"
  else
    local -a volumes=()
    local vol
    while IFS= read -r vol; do
      [ -n "${vol}" ] && volumes+=("${vol}")
    done < <(enumerate_volumes "${compose_file}")

    if [ "${#volumes[@]}" -eq 0 ]; then
      warn "compose file declared zero volumes; nothing to copy"
    else
      log "enumerated ${#volumes[@]} volume(s) from ${compose_file}"
      local prefix
      for vol in "${volumes[@]}"; do
        # Volume names are `results-<prefix>`; strip the prefix.
        case "${vol}" in
          results-*) prefix="${vol#results-}" ;;
          *)
            warn "volume '${vol}' does not match results-<prefix> pattern; skipping"
            continue
            ;;
        esac
        copy_volume "${vol}" "${prefix}" "${RUN_ID}" "${raw_dir}"
      done
    fi
  fi

  # -----------------------------------------------------------------------
  # Concatenate per-SHA JSONLs
  # -----------------------------------------------------------------------
  concat_jsonls "${run_dir}"

  # -----------------------------------------------------------------------
  # Summary + symlink
  # -----------------------------------------------------------------------
  local summary_rc=0
  run_summary "${RUN_ID}" || summary_rc=$?
  update_latest_symlink "${RUN_ID}"

  if [ "${DRY_RUN}" -eq 1 ]; then
    log "DRY-RUN complete for run_id=${RUN_ID}"
    return 0
  fi

  # -----------------------------------------------------------------------
  # Final per-mode diagnostics
  # -----------------------------------------------------------------------
  local agent_n baseline_n
  agent_n="$(line_count "${run_dir}/agent.jsonl")"
  baseline_n="$(line_count "${run_dir}/baseline.jsonl")"

  printf 'AGGREGATE %s\n' "${RUN_ID}"
  printf '  agent.jsonl:    %s lines\n' "${agent_n}"
  printf '  baseline.jsonl: %s lines\n' "${baseline_n}"
  printf '  summary.json:   experiments/results/%s/summary.json\n' "${RUN_ID}"
  printf '  summary.md:     experiments/results/%s/summary.md\n' "${RUN_ID}"

  return "${summary_rc}"
}

main "$@"
